+export function listChannelAgentTools(params: {
+  cfg?: ClawdbotConfig;
+}): ChannelAgentTool[] {
+  // Channel docking: aggregate channel-owned tools (login, etc.).
+  const tools: ChannelAgentTool[] = [];
+  for (const plugin of listChannelPlugins()) {
+    const entry = plugin.agentTools;
+    if (!entry) continue;
